import type { Config } from 'jest';

/**
 * Integration test config (README §2.9). Runs against a real PostgreSQL + Redis
 * (CI `services` block or local docker-compose). Migrations are applied with
 * `prisma migrate deploy` before this suite runs.
 */
const config: Config = {
  displayName: 'integration',
  rootDir: '.',
  testEnvironment: 'node',
  testMatch: ['<rootDir>/test/integration/**/*.spec.ts'],
  transform: {
    '^.+\\.ts$': ['ts-jest', { tsconfig: '<rootDir>/tsconfig.json' }],
  },
  moduleNameMapper: {
    '^@smartcart/shared-types$':
      '<rootDir>/../../../packages/shared-types/src/index.ts',
  },
  // Integration tests touch I/O — give them room and run serially to avoid
  // cross-test DB contention.
  testTimeout: 30_000,
  maxWorkers: 1,
};

export default config;
